import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as n,o as i,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"เพิ่ม Google Drive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/google-drive.md","filePath":"th-TH/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"th-TH/upload/google-drive.md"};function c(p,e,h,g,u,m){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="เพิ่ม-google-drive-channel" tabindex="-1">เพิ่ม Google Drive Channel <a class="header-anchor" href="#เพิ่ม-google-drive-channel" aria-label="Permalink to &quot;เพิ่ม Google Drive Channel&quot;">​</a></h1><h2 id="สิ่งที่ต้องเตรียมก่อน" tabindex="-1">สิ่งที่ต้องเตรียมก่อน <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อน" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อน&quot;">​</a></h2><p>ก่อนเริ่ม ให้เตรียมสิ่งเหล่านี้:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>ทำไมต้องใช้</th></tr></thead><tbody><tr><td>Google account</td><td>ใช้ access Google Cloud และ authorize Google Drive</td></tr><tr><td>Google Cloud project</td><td>ใช้ enable Drive API และ create OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed ใช้รับ <code>Client ID</code>, <code>Client Secret</code> และ <code>Refresh Token</code></td></tr><tr><td>ImgBed domain ของคุณ</td><td>ใช้เป็น OAuth redirect URI ต้องตรงกับ domain ที่ใช้จริง</td></tr></tbody></table><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><h3 id="step-1-enable-google-drive-api" tabindex="-1">Step 1: Enable Google Drive API <a class="header-anchor" href="#step-1-enable-google-drive-api" aria-label="Permalink to &quot;Step 1: Enable Google Drive API&quot;">​</a></h3><ol><li>เปิด Google Cloud Console</li><li>สร้าง project ใหม่หรือเลือก existing project</li><li>ไปที่ <code>APIs &amp; Services</code></li><li>คลิก <code>Enable APIs and Services</code></li><li>ค้นหา <code>Google Drive API</code></li><li>เปิดแล้วคลิก enable</li></ol><h3 id="step-2-configure-oauth-consent-screen" tabindex="-1">Step 2: Configure OAuth Consent Screen <a class="header-anchor" href="#step-2-configure-oauth-consent-screen" aria-label="Permalink to &quot;Step 2: Configure OAuth Consent Screen&quot;">​</a></h3><ol><li>ใน Google Cloud เปิด <code>Google Auth Platform</code></li><li>กรอกข้อมูลพื้นฐานใน <code>Branding</code> เช่น app name, support email และ developer contact email</li><li>เปิด <code>Audience</code></li><li>สำหรับ self-hosted personal deployments ส่วนใหญ่ ให้เลือก <code>External</code></li><li>ถ้าเลือก <code>External</code> ให้เพิ่ม Google account ที่ต้องการ authorize ใน <code>Test users</code></li><li>เปิด <code>Data Access</code></li><li>เพิ่ม Google Drive permissions ที่ต้องใช้</li></ol><h3 id="step-3-สร้าง-oauth-2-0-client" tabindex="-1">Step 3: สร้าง OAuth 2.0 Client <a class="header-anchor" href="#step-3-สร้าง-oauth-2-0-client" aria-label="Permalink to &quot;Step 3: สร้าง OAuth 2.0 Client&quot;">​</a></h3><ol><li>ใน <code>Google Auth Platform</code> เปิด <code>Clients</code></li><li>สร้าง client ใหม่</li><li>ตั้ง application type เป็น <code>Web application</code></li><li>ตั้งชื่อ client ให้จำง่าย</li><li>สำหรับ authorized JavaScript origins ให้ใส่ ImgBed URL เช่น:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>สำหรับ authorized redirect URIs ให้ใส่:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>หลังสร้าง client แล้ว ให้ copy values เหล่านี้:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-ใส่-google-drive-channel" tabindex="-1">Step 4: ใส่ Google Drive Channel <a class="header-anchor" href="#step-4-ใส่-google-drive-channel" aria-label="Permalink to &quot;Step 4: ใส่ Google Drive Channel&quot;">​</a></h2><p>ใน Upload Settings เลือก <code>Google Drive</code> แล้วกรอก:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>ใส่อะไร</th></tr></thead><tbody><tr><td>Channel name</td><td>ชื่อที่จำง่าย เช่น <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID จาก Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret จาก Google Cloud</td></tr><tr><td>Refresh Token</td><td>เว้นว่างไว้ก่อน รับใน step ถัดไป</td></tr><tr><td>Root directory</td><td>Optional ค่าเริ่มต้นคือ <code>imgbed</code></td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-รับ-refresh-token" tabindex="-1">Step 5: รับ Refresh Token <a class="header-anchor" href="#step-5-รับ-refresh-token" aria-label="Permalink to &quot;Step 5: รับ Refresh Token&quot;">​</a></h2><ol><li>คลิก <code>Get Token</code></li><li>เลือก Google account ที่ต้องการเชื่อมต่อ</li><li>ทำ authorization prompts ให้เสร็จ</li><li>Callback page จะแสดง <code>Refresh Token</code></li><li>Copy token นั้น</li><li>กลับไปที่ ImgBed แล้ว paste ใน field <code>Refresh Token</code></li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>ถ้าภายหลังเปลี่ยน Google account, เปลี่ยน OAuth client หรือ authorization เก่าหมดอายุ ไม่จำเป็นต้องลบ channel เปิด edit page แล้วคลิก <code>Reauthorize</code></p><h2 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h2><p>เมื่อกรอกครบทุก field แล้วให้ save channel</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เปิด Google Cloud</span></span>
<span class="line"><span>-&gt; Create หรือ select project</span></span>
<span class="line"><span>-&gt; Enable Google Drive API</span></span>
<span class="line"><span>-&gt; Configure Google Auth Platform</span></span>
<span class="line"><span>-&gt; ถ้า Audience เป็น External ให้เพิ่ม Google account ใน Test users</span></span>
<span class="line"><span>-&gt; สร้าง Web application OAuth client</span></span>
<span class="line"><span>-&gt; ใช้ https://your-domain.com/api/oauth/google/callback เป็น redirect URI</span></span>
<span class="line"><span>-&gt; ใส่ Client ID และ Client Secret ใน ImgBed</span></span>
<span class="line"><span>-&gt; คลิก Get Token</span></span>
<span class="line"><span>-&gt; Sign in ด้วย Google และ authorize</span></span>
<span class="line"><span>-&gt; Copy Refresh Token จาก callback page</span></span>
<span class="line"><span>-&gt; Paste กลับเข้า ImgBed แล้ว save</span></span>
<span class="line"><span>-&gt; Upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const k=n(d,[["render",c]]);export{f as __pageData,k as default};
